const express = require('express');
const app = express();
const PORT = 3000;

// Middleware parsers
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// Archivos estáticos
app.use(express.static('public'));

// GET: leer query string ?nom=Maria
app.get('/api/hola', (req, res) => {
  const nom = req.query.nom || 'mundo';
  res.json({ mensaje: `Hola, ${nom}!` });
});

// POST: recibir datos en el body
app.post('/api/eco', (req, res) => {
  res.status(201).json({ recibido: true, datos: req.body });
});

// 404
app.use('/api', (req, res) => {
  res.status(404).json({ error: 'Ruta no encontrada' });
});

app.listen(PORT, () => {
  console.log(`Servidor en http://localhost:${PORT}`);
});

