const sqlite3 = require('sqlite3');
const db = new sqlite3.Database('./datos.db');

// Crear tabla
db.run(`CREATE TABLE IF NOT EXISTS contactos (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  nom TEXT NOT NULL,
  correu TEXT NOT NULL
)`);

// Ruta POST
app.post('/formulario', (req, res) => {
  const { nom, correu } = req.body;
  if (!nom || !correu) return res.status(400).send('Faltan campos');
  db.run('INSERT INTO contactos (nom, correu) VALUES (?, ?)', [nom, correu]);
  res.send(`<h2>Datos recibidos</h2><p>Nombre: ${nom}</p><p>Correo: ${correu}</p>`);
});
